import { SeedApiClient } from "../../../src/Client";
import { mockServerPool } from "../../mock-server/MockServerPool";

describe("AuthClient", () => {
    test("getToken", async () => {
        const server = mockServerPool.createServer();
        const client = new SeedApiClient({
            maxRetries: 0,
            token: "test",
            apiVersion: "test",
            apiKey: "test",
            environment: { base: server.baseUrl, auth: server.baseUrl, upload: server.baseUrl },
        });

        const rawResponseBody = {
            access_token: "access_token",
            token_type: "token_type",
            expires_in: 1,
            scope: "scope",
        };

        server.mockEndpoint().post("/token").respondWith().statusCode(200).jsonBody(rawResponseBody).build();

        const response = await client.inferredAuthImplicitApiKey.auth.getToken();
        expect(response).toEqual({
            body: rawResponseBody,
            ok: true,
            headers: expect.any(Object),
            rawResponse: expect.any(Object),
        });
    });
});
